const CameraRecorder: FC<{ onClose: () => void; onVideoRecorded: (blob: Blob) => void; }> = ({ onClose, onVideoRecorded }) => {
    const videoRef = useRef<HTMLVideoElement>(null);
    const mediaRecorderRef = useRef<MediaRecorder | null>(null);
    const streamRef = useRef<MediaStream | null>(null);
    const recordedChunksRef = useRef<Blob[]>([]);

    const [isRecording, setIsRecording] = useState(false);
    const [recordedBlobUrl, setRecordedBlobUrl] = useState<string>('');
    const [countdown, setCountdown] = useState(10);
    const [error, setError] = useState<string>('');

    useEffect(() => {
        async function setupCamera() {
            try {
                const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
                streamRef.current = stream;
                if (videoRef.current) {
                    videoRef.current.srcObject = stream;
                }
            } catch (err) {
                console.error("Error accessing camera:", err);
                setError("Could not access camera. Please check permissions and try again.");
            }
        }
        setupCamera();

        return () => {
            streamRef.current?.getTracks().forEach(track => track.stop());
        };
    }, []);

    useEffect(() => {
        let interval: number;
        if (isRecording) {
            setCountdown(10);
            interval = window.setInterval(() => {
                setCountdown(prev => {
                    if (prev <= 1) {
                        stopRecording();
                        return 0;
                    }
                    return prev - 1;
                });
            }, 1000);
        }
        return () => clearInterval(interval);
    }, [isRecording]);

    const startRecording = () => {
        if (!streamRef.current) return;
        setRecordedBlobUrl('');
        recordedChunksRef.current = [];
        const recorder = new MediaRecorder(streamRef.current);
        mediaRecorderRef.current = recorder;
        recorder.ondataavailable = (event) => {
            if (event.data.size > 0) {
                recordedChunksRef.current.push(event.data);
            }
        };
        recorder.onstop = () => {
            const blob = new Blob(recordedChunksRef.current, { type: 'video/webm' });
            const url = URL.createObjectURL(blob);
            setRecordedBlobUrl(url);
            setIsRecording(false);
        };
        recorder.start();
        setIsRecording(true);
    };

    const stopRecording = () => {
        mediaRecorderRef.current?.stop();
    };

    const handleUseVideo = async () => {
        if (!recordedBlobUrl) return;
        const blob = await fetch(recordedBlobUrl).then(r => r.blob());
        onVideoRecorded(blob);
    };

    if (error) {
        return (
            <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50">
                <div className="bg-[#221933] p-8 rounded-lg text-center">
                    <p className="text-red-400 mb-4">{error}</p>
                    <button onClick={onClose} className="px-4 py-2 bg-primary rounded-md text-white">Close</button>
                </div>
            </div>
        );
    }

    return (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex flex-col items-center justify-center z-50 p-4">
            <div className="relative w-full max-w-3xl aspect-video bg-black rounded-lg overflow-hidden border-2 border-white/10">
                <video ref={videoRef} autoPlay muted playsInline className="w-full h-full object-cover" src={recordedBlobUrl || undefined}></video>
                {isRecording && (
                    <div className="absolute top-4 left-4 flex items-center gap-2 bg-red-600 text-white px-3 py-1 rounded-full text-sm font-bold">
                        <span className="relative flex h-3 w-3">
                            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-white opacity-75"></span>
                            <span className="relative inline-flex rounded-full h-3 w-3 bg-white"></span>
                        </span>
                        <span>REC</span>
                        <span>0:{countdown.toString().padStart(2, '0')}</span>
                    </div>
                )}
            </div>
            <div className="mt-6 flex items-center justify-center gap-4">
                {!recordedBlobUrl ? (
                    <>
                        <button onClick={onClose} className="px-6 py-3 bg-white/10 hover:bg-white/20 rounded-full font-semibold text-white transition-colors duration-300">Cancel</button>
                        <button onClick={isRecording ? stopRecording : startRecording} className={`w-20 h-20 rounded-full flex items-center justify-center transition-all ${isRecording ? 'bg-white' : 'bg-red-600'}`}>
                            <div className={`transition-all duration-200 ${isRecording ? 'bg-red-600 w-8 h-8 rounded-md' : 'bg-white w-16 h-16 rounded-full'}`}></div>
                        </button>
                    </>
                ) : (
                    <>
                        <button onClick={() => setRecordedBlobUrl('')} className="px-6 py-3 bg-white/10 hover:bg-white/20 rounded-full font-semibold text-white transition-colors duration-300">Record Again</button>
                        <button onClick={handleUseVideo} className="px-6 py-3 bg-primary hover:brightness-110 rounded-full font-semibold text-white transition-colors duration-300">Use this Video</button>
                    </>
                )}
            </div>
        </div>
    );
};

