    return new Promise<string>((resolve, reject) => {
        const video = videoRef.current;
        if (!video) {
            return reject(new Error("Video element not found."));
        }

        video.onloadeddata = () => {
            video.onseeked = () => {
                const canvas = canvasRef.current;
                const ctx = canvas?.getContext('2d');
                if (canvas && ctx && video) {
                    canvas.width = video.videoWidth;
                    canvas.height = video.videoHeight;
                    ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
                    resolve(canvas.toDataURL('image/jpeg', 0.9));
                } else {
                    reject(new Error("Failed to get canvas context."));
                }
                video.onseeked = null;
                video.onerror = null;
            };
            video.onerror = () => reject(new Error("Error seeking video for frame extraction."));
            video.currentTime = (video.duration > 1) ? 1 : video.duration / 2;
        };
        video.onerror = () => reject(new Error("Error loading video for frame extraction."));
        if (video.readyState >= 3) { // HAVE_FUTURE_DATA
            video.onloadeddata = null; 
            video.onseeked = () => {
                const canvas = canvasRef.current;
                const ctx = canvas?.getContext('2d');
                if (canvas && ctx && video) {
                    canvas.width = video.videoWidth;
                    canvas.height = video.videoHeight;
