  const isProcessing = status === AppStatus.GENERATING_PROMPT || status === AppStatus.GENERATING_VIDEO || status === AppStatus.REMIXING_IMAGE || status === AppStatus.FETCHING_VIDEO || status === AppStatus.ENHANCING_PROMPT || status === AppStatus.VIDEO_LOADING || status === AppStatus.LOADING_TEMPLATE || status === AppStatus.GENERATING_AUDIO || status === AppStatus.ANALYZING_IMAGE || status === AppStatus.ANALYZING_VIDEO;

  const timeAgo = (dateString: string): string => {
    const date = new Date(dateString);
    const now = new Date();
    const seconds = Math.floor((now.getTime() - date.getTime()) / 1000);

    let interval = seconds / 31536000;
    if (interval > 1) return Math.floor(interval) + " years ago";
    interval = seconds / 2592000;
    if (interval > 1) return Math.floor(interval) + " months ago";
    interval = seconds / 86400;
    if (interval > 1) return Math.floor(interval) + " days ago";
    interval = seconds / 3600;
    if (interval > 1) return Math.floor(interval) + " hours ago";
    interval = seconds / 60;
    if (interval > 1) return Math.floor(interval) + " minutes ago";
    return "just now";
  }

  const renderCreationContent = () => (
    <div className="flex-grow flex items-center justify-center p-4 sm:p-6 lg:p-8">
        <div className="w-full max-w-4xl bg-white/60 dark:bg-[#221933]/80 rounded-2xl shadow-2xl shadow-black/30 backdrop-blur-sm border border-black/10 dark:border-[#2f2348] p-6 sm:p-8">
            <div className="w-full space-y-8">
