// Helper to resize images for faster processing
const resizeImage = (url: string, maxDimension: number = 1024): Promise<string> => {
    return new Promise((resolve, reject) => {
        const img = new Image();
        img.crossOrigin = "Anonymous";
        img.onload = () => {
            let width = img.width;
            let height = img.height;

            if (width > height) {
                if (width > maxDimension) {
                    height *= maxDimension / width;
                    width = maxDimension;
                }
            } else {
                if (height > maxDimension) {
                    width *= maxDimension / height;
                    height = maxDimension;
                }
            }

            const canvas = document.createElement('canvas');
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d');
            if (!ctx) {
                reject(new Error("Could not get canvas context"));
                return;
            }
            ctx.drawImage(img, 0, 0, width, height);
            resolve(canvas.toDataURL('image/jpeg', 0.8));
        };
        img.onerror = (e) => reject(e);
        img.src = url;
    });
};

// --- Autocompletion logic ---
const customAutocomplete = (context: CompletionContext): CompletionResult | null => {
  const word = context.matchBefore(/\w*/);

  if (!word || (word.from === word.to && !context.explicit)) {
    return null;
  }

  const typed = word.text.toLowerCase();
  const options = PROMPT_KEYWORD_SUGGESTIONS
    .filter(keyword => keyword.label.toLowerCase().startsWith(typed))
    .map(keyword => ({
      label: keyword.label,
      type: keyword.category.toLowerCase(),
      detail: keyword.category,
      info: () => {
        const tooltip = document.createElement('div');
        tooltip.className = 'cm-tooltip-info';
        tooltip.textContent = keyword.description;
        return tooltip;
      },
    }));

  if (options.length === 0) {
    return null;
  }

  return {
    from: word.from,
    options,
    validFor: /^\w*$/,
  };
};

