  const extractFrameFromVideo = useCallback(() => {
    return new Promise<string>((resolve, reject) => {
        const video = videoRef.current;
        if (!video) {
            return reject(new Error("Video element not found."));
        }

        const captureFrame = () => {
            const canvas = canvasRef.current;
            const ctx = canvas?.getContext('2d');
            if (canvas && ctx && video) {
                // Resize logic
                const MAX_DIMENSION = 1024;
                let width = video.videoWidth;
                let height = video.videoHeight;

                if (width > height) {
                    if (width > MAX_DIMENSION) {
                        height *= MAX_DIMENSION / width;
                        width = MAX_DIMENSION;
                    }
                } else {
                    if (height > MAX_DIMENSION) {
                        width *= MAX_DIMENSION / height;
                        height = MAX_DIMENSION;
                    }
                }

                canvas.width = width;
                canvas.height = height;
                ctx.drawImage(video, 0, 0, width, height);
                resolve(canvas.toDataURL('image/jpeg', 0.8)); // Lower quality slightly for speed
            } else {
                reject(new Error("Failed to get canvas context."));
            }
        };

        if (video.readyState >= 3) { // HAVE_FUTURE_DATA
            captureFrame();
        } else {
            video.onloadeddata = () => {
                video.onseeked = () => {
                    captureFrame();
                    video.onseeked = null;
                };
                video.currentTime = (video.duration > 1) ? 1 : video.duration / 2;
            };
            video.onerror = () => reject(new Error("Error loading video for frame extraction."));
            // Trigger load
            video.currentTime = (video.duration > 1) ? 1 : video.duration / 2;
        }
    });
  }, []);

