    // --- Audio Utility Functions ---
    const decode = (base64: string): Uint8Array => {
        const binaryString = atob(base64);
        const len = binaryString.length;
        const bytes = new Uint8Array(len);
        for (let i = 0; i < len; i++) {
            bytes[i] = binaryString.charCodeAt(i);
        }
        return bytes;
    };

    const decodeAudioData = async (
        data: Uint8Array,
        ctx: AudioContext,
        sampleRate: number,
        numChannels: number,
    ): Promise<AudioBuffer> => {
        const dataInt16 = new Int16Array(data.buffer);
        const frameCount = dataInt16.length / numChannels;
        const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

        for (let channel = 0; channel < numChannels; channel++) {
            const channelData = buffer.getChannelData(channel);
            for (let i = 0; i < frameCount; i++) {
                channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
            }
        }
        return buffer;
    };

    const audioBufferToWav = (buffer: AudioBuffer): string => {
        const sampleRate = buffer.sampleRate;
        const channelData = buffer.getChannelData(0); // Mono
        const numSamples = channelData.length;

        const bufferArr = new ArrayBuffer(44 + numSamples * 2);
        const view = new DataView(bufferArr);

        // RIFF chunk descriptor
        writeString(view, 0, 'RIFF');
        view.setUint32(4, 36 + numSamples * 2, true);
        writeString(view, 8, 'WAVE');
        // "fmt " sub-chunk
        writeString(view, 12, 'fmt ');
        view.setUint32(16, 16, true); // subchunk 1 size
        view.setUint16(20, 1, true); // audio format 1 = PCM
        view.setUint16(22, 1, true); // number of channels
        view.setUint32(24, sampleRate, true);
        view.setUint32(28, sampleRate * 2, true); // byte rate
        view.setUint16(32, 2, true); // block align
        view.setUint16(34, 16, true); // bits per sample
        // "data" sub-chunk
        writeString(view, 36, 'data');
        view.setUint32(40, numSamples * 2, true);

        // write the PCM samples
        let offset = 44;
        for (let i = 0; i < numSamples; i++, offset += 2) {
            const s = Math.max(-1, Math.min(1, channelData[i]));
            view.setInt16(offset, s < 0 ? s * 0x8000 : s * 0x7FFF, true);
        }

        function writeString(view: DataView, offset: number, string: string) {
            for (let i = 0; i < string.length; i++) {
                view.setUint8(offset + i, string.charCodeAt(i));
            }
        }

        const wavBlob = new Blob([view], { type: 'audio/wav' });
        return URL.createObjectURL(wavBlob);
    };

    const handleGenerateSpeech = async () => {
        if (!ttsText.trim()) return;

        const parentStatus = status;
        setStatus(AppStatus.GENERATING_AUDIO);
        setError('');

        try {
            const base64Audio = await generateSpeech(ttsText);
            const outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
            const decodedBytes = decode(base64Audio);
            const audioBuffer = await decodeAudioData(decodedBytes, outputAudioContext, 24000, 1);
            const wavUrl = audioBufferToWav(audioBuffer);
            setGeneratedAudioUrl(wavUrl);
        } catch (e) {
            const err = e as Error;
            setError(`Failed to generate speech: ${err.message}`);
        } finally {
            setStatus(parentStatus);
        }
    };

  const urlToDataUrl = (url: string): Promise<string> => {
    if (url.startsWith('data:')) {
      return Promise.resolve(url);
    }
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.crossOrigin = 'Anonymous';
      img.onload = () => {
        const canvas = document.createElement('canvas');
        canvas.width = img.width;
        canvas.height = img.height;
        const ctx = canvas.getContext('2d');
        if (!ctx) {
          return reject(new Error('Could not get canvas context'));
        }
        ctx.drawImage(img, 0, 0);
        resolve(canvas.toDataURL('image/png'));
      };
      img.onerror = () => {
        reject(new Error('Failed to load image from URL. This may be due to a network error or CORS policy.'));
      };
      img.src = url;
    });
  };

