            await updateUser({ fullName, profilePicture });
            setMessage({ type: 'success', text: 'Studio Profile updated successfully.' });
        } catch (err) {
            setMessage({ type: 'error', text: 'Critical failure during profile update.' });
        } finally {
            setIsLoading(false);
        }
